// Generated by Cursor AI for jjmil on 2026-03-22.
using System.Collections.Generic;
using TMPro;
using UnityEngine;
using UnityEngine.UI;

/// <summary>
/// Drives the battle-pass-style progression track UI.
/// Attach to the Progression panel in the main menu scene.
/// Reads tier data from <see cref="ProgressionConfig"/> and
/// unlock / XP state from <see cref="ProgressionService"/>.
/// </summary>
public sealed class ProgressionScreenController : MonoBehaviour
{
    [Header("Config")]
    [Tooltip(
        "Progression config asset. Falls back to "
        + "ProgressionService.Config if left null.")]
    [SerializeField] private ProgressionConfig config;

    [Header("XP Header")]
    [Tooltip(
        "Text that displays the player's lifetime XP total.")]
    [SerializeField] private TMP_Text xpTotalText;

    [Tooltip("Text showing progress toward the next unlock.")]
    [SerializeField] private TMP_Text nextUnlockText;

    [Header("Track")]
    [Tooltip(
        "ScrollRect that contains the tier track. "
        + "Auto-created if left null.")]
    [SerializeField] private ScrollRect trackScrollRect;

    [Tooltip(
        "Content transform inside the scroll view where tier "
        + "nodes are instantiated. Auto-created if left null.")]
    [SerializeField] private RectTransform trackContent;

    [Header("Tier Node Prefab (optional)")]
    [Tooltip(
        "If set, instantiated per tier. Must have children "
        + "named Icon (Image), Name (TMP_Text), Threshold "
        + "(TMP_Text), Lock (GameObject), and ProgressFill "
        + "(Image). If left null nodes are built in code.")]
    [SerializeField] private GameObject tierNodePrefab;

    [Header("Appearance")]
    [SerializeField] private float nodeWidth = 160f;
    [SerializeField] private float nodeHeight = 200f;
    [SerializeField] private float nodeSpacing = 40f;
    [SerializeField] private Color unlockedColor =
        new Color(0.2f, 0.75f, 0.35f, 1f);
    [SerializeField] private Color lockedColor =
        new Color(0.35f, 0.35f, 0.35f, 1f);
    [SerializeField] private Color progressBarBgColor =
        new Color(0.2f, 0.2f, 0.2f, 1f);
    [SerializeField] private Color progressBarFillColor =
        new Color(0.95f, 0.75f, 0.15f, 1f);

    private readonly List<TierNodeRefs> _nodeRefs =
        new List<TierNodeRefs>();

    private sealed class TierNodeRefs
    {
        public RectTransform root;
        public Image iconImage;
        public TMP_Text nameText;
        public TMP_Text thresholdText;
        public GameObject lockOverlay;
        public Image progressFill;
    }

    private void OnEnable()
    {
        Refresh();
    }

    public void Refresh()
    {
        EnsureConfig();
        EnsureTrackLayout();
        RebuildNodes();
        UpdateNodeStates();
        UpdateHeaderTexts();
    }

    private void EnsureConfig()
    {
        if (config != null)
        {
            return;
        }

        if (ProgressionService.Instance != null)
        {
            config = ProgressionService.Instance.Config;
        }
    }

    private void EnsureTrackLayout()
    {
        if (trackScrollRect != null && trackContent != null)
        {
            return;
        }

        if (trackScrollRect == null)
        {
            trackScrollRect =
                GetComponentInChildren<ScrollRect>(true);
        }

        if (trackScrollRect == null)
        {
            var scrollGo = new GameObject(
                "TrackScroll",
                typeof(RectTransform),
                typeof(ScrollRect),
                typeof(Image),
                typeof(Mask));

            scrollGo.transform.SetParent(transform, false);

            var scrollRect =
                scrollGo.GetComponent<RectTransform>();
            scrollRect.anchorMin = new Vector2(0f, 0.05f);
            scrollRect.anchorMax = new Vector2(1f, 0.7f);
            scrollRect.offsetMin = new Vector2(40f, 0f);
            scrollRect.offsetMax = new Vector2(-40f, 0f);

            var scrollBg = scrollGo.GetComponent<Image>();
            scrollBg.color = new Color(0.1f, 0.1f, 0.1f, 0.6f);

            var mask = scrollGo.GetComponent<Mask>();
            mask.showMaskGraphic = true;

            trackScrollRect =
                scrollGo.GetComponent<ScrollRect>();
            trackScrollRect.horizontal = true;
            trackScrollRect.vertical = false;
            trackScrollRect.movementType =
                ScrollRect.MovementType.Elastic;

            var viewportGo = new GameObject(
                "Viewport",
                typeof(RectTransform));

            viewportGo.transform.SetParent(
                scrollGo.transform, false);

            var vpRect =
                viewportGo.GetComponent<RectTransform>();
            vpRect.anchorMin = Vector2.zero;
            vpRect.anchorMax = Vector2.one;
            vpRect.offsetMin = Vector2.zero;
            vpRect.offsetMax = Vector2.zero;

            trackScrollRect.viewport = vpRect;
        }

        if (trackContent == null)
        {
            var contentGo = new GameObject(
                "Content",
                typeof(RectTransform),
                typeof(HorizontalLayoutGroup),
                typeof(ContentSizeFitter));

            Transform parent = trackScrollRect.viewport != null
                ? trackScrollRect.viewport
                : trackScrollRect.transform;

            contentGo.transform.SetParent(parent, false);

            trackContent =
                contentGo.GetComponent<RectTransform>();
            trackContent.anchorMin = new Vector2(0f, 0f);
            trackContent.anchorMax = new Vector2(0f, 1f);
            trackContent.pivot = new Vector2(0f, 0.5f);
            trackContent.offsetMin = Vector2.zero;
            trackContent.offsetMax = Vector2.zero;

            var hlg =
                contentGo.GetComponent<HorizontalLayoutGroup>();
            hlg.childAlignment = TextAnchor.MiddleLeft;
            hlg.childControlWidth = false;
            hlg.childControlHeight = false;
            hlg.childForceExpandWidth = false;
            hlg.childForceExpandHeight = false;
            hlg.spacing = nodeSpacing;
            hlg.padding = new RectOffset(20, 20, 10, 10);

            var csf =
                contentGo.GetComponent<ContentSizeFitter>();
            csf.horizontalFit =
                ContentSizeFitter.FitMode.PreferredSize;
            csf.verticalFit =
                ContentSizeFitter.FitMode.Unconstrained;

            trackScrollRect.content = trackContent;
        }
    }

    private void RebuildNodes()
    {
        for (int i = _nodeRefs.Count - 1; i >= 0; i--)
        {
            if (_nodeRefs[i].root != null)
            {
                Destroy(_nodeRefs[i].root.gameObject);
            }
        }

        _nodeRefs.Clear();

        if (config == null)
        {
            return;
        }

        var starters = config.StarterBalls;

        for (int i = 0; i < starters.Count; i++)
        {
            if (starters[i] == null)
            {
                continue;
            }

            var node = BuildNode(
                starters[i], 0d, isStarter: true);

            _nodeRefs.Add(node);
        }

        var tiers = config.Tiers;

        for (int i = 0; i < tiers.Count; i++)
        {
            if (tiers[i] == null || !tiers[i].HasValidReward)
            {
                continue;
            }

            var node = BuildNode(
                tiers[i].RewardBall,
                tiers[i].XpThreshold,
                isStarter: false);

            _nodeRefs.Add(node);
        }
    }

    private TierNodeRefs BuildNode(
        BallDefinition ball,
        double xpThreshold,
        bool isStarter)
    {
        if (tierNodePrefab != null)
        {
            return BuildNodeFromPrefab(
                ball, xpThreshold, isStarter);
        }

        return BuildNodeFromCode(
            ball, xpThreshold, isStarter);
    }

    private TierNodeRefs BuildNodeFromPrefab(
        BallDefinition ball,
        double xpThreshold,
        bool isStarter)
    {
        var go = Instantiate(tierNodePrefab, trackContent);
        var refs = new TierNodeRefs
        {
            root = go.GetComponent<RectTransform>()
        };

        var images = go.GetComponentsInChildren<Image>(true);

        for (int i = 0; i < images.Length; i++)
        {
            if (images[i].gameObject.name == "Icon")
            {
                refs.iconImage = images[i];
            }
            else if (images[i].gameObject.name == "ProgressFill")
            {
                refs.progressFill = images[i];
            }
        }

        var texts =
            go.GetComponentsInChildren<TMP_Text>(true);

        for (int i = 0; i < texts.Length; i++)
        {
            if (texts[i].gameObject.name == "Name")
            {
                refs.nameText = texts[i];
            }
            else if (texts[i].gameObject.name == "Threshold")
            {
                refs.thresholdText = texts[i];
            }
        }

        var lockT = go.transform.Find("Lock");

        if (lockT != null)
        {
            refs.lockOverlay = lockT.gameObject;
        }

        ApplyNodeData(refs, ball, xpThreshold, isStarter);
        return refs;
    }

    private TierNodeRefs BuildNodeFromCode(
        BallDefinition ball,
        double xpThreshold,
        bool isStarter)
    {
        var nodeGo = new GameObject(
            "TierNode_" + ball.GetSafeDisplayName(),
            typeof(RectTransform),
            typeof(Image),
            typeof(LayoutElement));

        nodeGo.transform.SetParent(trackContent, false);

        var nodeRect = nodeGo.GetComponent<RectTransform>();
        nodeRect.sizeDelta =
            new Vector2(nodeWidth, nodeHeight);

        var le = nodeGo.GetComponent<LayoutElement>();
        le.preferredWidth = nodeWidth;
        le.preferredHeight = nodeHeight;

        var nodeBg = nodeGo.GetComponent<Image>();
        nodeBg.color = lockedColor;

        var refs = new TierNodeRefs { root = nodeRect };

        float iconSize = nodeWidth * 0.55f;
        var iconGo = new GameObject(
            "Icon",
            typeof(RectTransform),
            typeof(Image));

        iconGo.transform.SetParent(nodeGo.transform, false);

        var iconRect = iconGo.GetComponent<RectTransform>();
        iconRect.anchorMin = new Vector2(0.5f, 1f);
        iconRect.anchorMax = new Vector2(0.5f, 1f);
        iconRect.pivot = new Vector2(0.5f, 1f);
        iconRect.anchoredPosition = new Vector2(0f, -12f);
        iconRect.sizeDelta =
            new Vector2(iconSize, iconSize);

        refs.iconImage = iconGo.GetComponent<Image>();

        refs.nameText = CreateNodeText(
            nodeGo.transform,
            "Name",
            new Vector2(0.5f, 0.35f),
            18f);

        refs.thresholdText = CreateNodeText(
            nodeGo.transform,
            "Threshold",
            new Vector2(0.5f, 0.18f),
            14f);

        var progressBg = new GameObject(
            "ProgressBg",
            typeof(RectTransform),
            typeof(Image));

        progressBg.transform.SetParent(
            nodeGo.transform, false);

        var pBgRect =
            progressBg.GetComponent<RectTransform>();
        pBgRect.anchorMin = new Vector2(0.1f, 0.02f);
        pBgRect.anchorMax = new Vector2(0.9f, 0.1f);
        pBgRect.offsetMin = Vector2.zero;
        pBgRect.offsetMax = Vector2.zero;

        progressBg.GetComponent<Image>().color =
            progressBarBgColor;

        var fillGo = new GameObject(
            "ProgressFill",
            typeof(RectTransform),
            typeof(Image));

        fillGo.transform.SetParent(
            progressBg.transform, false);

        var fillRect = fillGo.GetComponent<RectTransform>();
        fillRect.anchorMin = Vector2.zero;
        fillRect.anchorMax = new Vector2(0f, 1f);
        fillRect.offsetMin = Vector2.zero;
        fillRect.offsetMax = Vector2.zero;

        refs.progressFill = fillGo.GetComponent<Image>();
        refs.progressFill.color = progressBarFillColor;

        var lockGo = new GameObject(
            "Lock",
            typeof(RectTransform),
            typeof(Image));

        lockGo.transform.SetParent(nodeGo.transform, false);

        var lockRect = lockGo.GetComponent<RectTransform>();
        lockRect.anchorMin = Vector2.zero;
        lockRect.anchorMax = Vector2.one;
        lockRect.offsetMin = Vector2.zero;
        lockRect.offsetMax = Vector2.zero;

        lockGo.GetComponent<Image>().color =
            new Color(0f, 0f, 0f, 0.55f);

        var lockLabel = new GameObject(
            "LockLabel",
            typeof(RectTransform),
            typeof(TextMeshProUGUI));

        lockLabel.transform.SetParent(
            lockGo.transform, false);

        var llRect =
            lockLabel.GetComponent<RectTransform>();
        llRect.anchorMin = Vector2.zero;
        llRect.anchorMax = Vector2.one;
        llRect.offsetMin = Vector2.zero;
        llRect.offsetMax = Vector2.zero;

        var llText =
            lockLabel.GetComponent<TextMeshProUGUI>();
        llText.text = "LOCKED";
        llText.fontSize = 22f;
        llText.alignment = TextAlignmentOptions.Center;
        llText.color = Color.white;

        refs.lockOverlay = lockGo;

        ApplyNodeData(refs, ball, xpThreshold, isStarter);
        return refs;
    }

    private static TMP_Text CreateNodeText(
        Transform parent,
        string name,
        Vector2 anchorCenter,
        float fontSize)
    {
        var go = new GameObject(
            name,
            typeof(RectTransform),
            typeof(TextMeshProUGUI));

        go.transform.SetParent(parent, false);

        var rect = go.GetComponent<RectTransform>();
        rect.anchorMin =
            new Vector2(0f, anchorCenter.y - 0.06f);
        rect.anchorMax =
            new Vector2(1f, anchorCenter.y + 0.06f);
        rect.offsetMin = new Vector2(4f, 0f);
        rect.offsetMax = new Vector2(-4f, 0f);

        var text = go.GetComponent<TextMeshProUGUI>();
        text.fontSize = fontSize;
        text.alignment = TextAlignmentOptions.Center;
        text.color = Color.white;
        text.textWrappingMode = TextWrappingModes.NoWrap;
        text.overflowMode = TextOverflowModes.Ellipsis;

        return text;
    }

    private static void ApplyNodeData(
        TierNodeRefs refs,
        BallDefinition ball,
        double xpThreshold,
        bool isStarter)
    {
        if (refs.iconImage != null && ball.Icon != null)
        {
            refs.iconImage.sprite = ball.Icon;
        }

        if (refs.nameText != null)
        {
            refs.nameText.text = ball.GetSafeDisplayName();
        }

        if (refs.thresholdText != null)
        {
            refs.thresholdText.text = isStarter
                ? "Starter"
                : FormatXp(xpThreshold);
        }
    }

    private void UpdateNodeStates()
    {
        if (config == null)
        {
            return;
        }

        double xp = ProgressionService.Instance != null
            ? ProgressionService.Instance.GetCurrentXp()
            : 0d;

        int starterCount = 0;

        for (int i = 0; i < config.StarterBalls.Count; i++)
        {
            if (config.StarterBalls[i] != null)
            {
                starterCount++;
            }
        }

        for (int i = 0; i < _nodeRefs.Count; i++)
        {
            var refs = _nodeRefs[i];
            bool isStarter = i < starterCount;
            bool unlocked = isStarter;

            double tierThreshold = 0d;
            double prevThreshold = 0d;

            if (!isStarter)
            {
                int tierIdx = i - starterCount;

                if (tierIdx >= 0
                    && tierIdx < config.Tiers.Count)
                {
                    var tier = config.Tiers[tierIdx];
                    tierThreshold = tier.XpThreshold;
                    unlocked = xp >= tierThreshold;

                    prevThreshold = tierIdx > 0
                        ? config.Tiers[tierIdx - 1].XpThreshold
                        : 0d;
                }
            }

            if (refs.lockOverlay != null)
            {
                refs.lockOverlay.SetActive(!unlocked);
            }

            var bg = refs.root.GetComponent<Image>();

            if (bg != null)
            {
                bg.color =
                    unlocked ? unlockedColor : lockedColor;
            }

            if (refs.progressFill != null)
            {
                float fill;

                if (isStarter || unlocked)
                {
                    fill = 1f;
                }
                else
                {
                    double range =
                        tierThreshold - prevThreshold;

                    fill = range > 0d
                        ? Mathf.Clamp01(
                            (float)((xp - prevThreshold)
                                / range))
                        : 0f;
                }

                refs.progressFill.rectTransform.anchorMax =
                    new Vector2(fill, 1f);
            }
        }
    }

    private void UpdateHeaderTexts()
    {
        double xp = ProgressionService.Instance != null
            ? ProgressionService.Instance.GetCurrentXp()
            : 0d;

        if (xpTotalText != null)
        {
            xpTotalText.text =
                $"Total XP: {FormatXp(xp)}";
        }

        if (nextUnlockText != null)
        {
            ProgressionTier next =
                ProgressionService.Instance != null
                    ? ProgressionService.Instance
                        .GetNextLockedTier()
                    : null;

            if (next != null && next.RewardBall != null)
            {
                double remaining =
                    next.XpThreshold - xp;

                nextUnlockText.text =
                    $"Next: {next.RewardBall.GetSafeDisplayName()}"
                    + $" in {FormatXp(remaining)}";
            }
            else
            {
                nextUnlockText.text = "All balls unlocked!";
            }
        }
    }

    private static string FormatXp(double value)
    {
        if (value >= 1_000_000d)
        {
            return $"{value / 1_000_000d:F1}M";
        }

        if (value >= 1_000d)
        {
            return $"{value / 1_000d:F1}K";
        }

        return $"{value:N0}";
    }
}
